     1вҶ’// FreeLang v6: Parser (Pratt / Recursive Descent)
     2вҶ’
     3вҶ’import { Token, TokenType as T } from "./token";
     4вҶ’import { Expr, Stmt, Program, MatchArm } from "./ast";
     5вҶ’
     6вҶ’export function parse(tokens: Token[]): Program {
     7вҶ’  let pos = 0;
     8вҶ’
     9вҶ’  function peek(): Token { return tokens[pos]; }
    10вҶ’  function advance(): Token { return tokens[pos++]; }
    11вҶ’  function expect(type: T, msg?: string): Token {
    12вҶ’    const t = advance();
    13вҶ’    if (t.type !== type) throw new Error(msg ?? `Expected ${T[type]}, got ${T[t.type]} '${t.value}' at line ${t.line}`);
    14вҶ’    return t;
    15вҶ’  }
    16вҶ’  function match(type: T): boolean { if (peek().type === type) { advance(); return true; } return false; }
    17вҶ’  function at(type: T): boolean { return peek().type === type; }
    18вҶ’
    19вҶ’  // --- Statements ---
    20вҶ’  function parseProgram(): Program {
    21вҶ’    const stmts: Stmt[] = [];
    22вҶ’    while (!at(T.EOF)) stmts.push(parseStmt());
    23вҶ’    return { stmts };
    24вҶ’  }
    25вҶ’
    26вҶ’  function parseStmt(): Stmt {
    27вҶ’    while (match(T.Semicolon)) {} // skip stray semicolons
    28вҶ’    if (at(T.EOF)) return { kind: "expr", expr: { kind: "null" } };
    29вҶ’    if (at(T.Let) || at(T.Const)) return parseLetStmt();
    30вҶ’    if (at(T.Fn)) return parseFnStmt();
    31вҶ’    if (at(T.Return)) return parseReturn();
    32вҶ’    if (at(T.If)) return parseIf();
    33вҶ’    if (at(T.While)) return parseWhile();
    34вҶ’    if (at(T.For)) return parseFor();
    35вҶ’    if (at(T.LBrace)) return parseBlock();
    36вҶ’    if (at(T.Print) || at(T.Println)) return parsePrint();
    37вҶ’    if (at(T.Break)) { advance(); match(T.Semicolon); return { kind: "break" }; }
    38вҶ’    if (at(T.Continue)) { advance(); match(T.Semicolon); return { kind: "continue" }; }
    39вҶ’    if (at(T.Try)) return parseTry();
    40вҶ’    if (at(T.Throw)) return parseThrow();
    41вҶ’    if (at(T.Struct)) return parseStruct();
    42вҶ’    if (at(T.Import)) return parseImport();
    43вҶ’    if (at(T.Export)) return parseExport();
    44вҶ’    if (at(T.Match)) return parseMatch();
    45вҶ’    return parseExprStmt();
    46вҶ’  }
    47вҶ’
    48вҶ’  function parseLetStmt(): Stmt {
    49вҶ’    const mutable = advance().type === T.Let;
    50вҶ’
    51вҶ’    // Object destructuring: let {a, b} = expr
    52вҶ’    if (at(T.LBrace)) {
    53вҶ’      advance();
    54вҶ’      const names: string[] = [];
    55вҶ’      while (!at(T.RBrace) && !at(T.EOF)) {
    56вҶ’        names.push(expect(T.Ident, "Expected destructured name").value);
    57вҶ’        match(T.Comma);
    58вҶ’      }
    59вҶ’      expect(T.RBrace);
    60вҶ’      expect(T.Assign, "Expected '=' after destructuring pattern");
    61вҶ’      const init = parseExpr();
    62вҶ’      match(T.Semicolon);
    63вҶ’      const tmp = `__d${pos}`;
    64вҶ’      return { kind: "multi", stmts: [
    65вҶ’        { kind: "let", name: tmp, mutable: false, init },
    66вҶ’        ...names.map(n => ({
    67вҶ’          kind: "let" as const, name: n, mutable,
    68вҶ’          init: { kind: "member" as const, object: { kind: "ident" as const, name: tmp }, property: n } as Expr,
    69вҶ’        }))
    70вҶ’      ]};
    71вҶ’    }
    72вҶ’
    73вҶ’    // Array destructuring: let [x, y] = expr
    74вҶ’    if (at(T.LBracket)) {
    75вҶ’      advance();
    76вҶ’      const names: string[] = [];
    77вҶ’      while (!at(T.RBracket) && !at(T.EOF)) {
    78вҶ’        names.push(expect(T.Ident, "Expected destructured name").value);
    79вҶ’        match(T.Comma);
    80вҶ’      }
    81вҶ’      expect(T.RBracket);
    82вҶ’      expect(T.Assign, "Expected '=' after destructuring pattern");
    83вҶ’      const init = parseExpr();
    84вҶ’      match(T.Semicolon);
    85вҶ’      const tmp = `__d${pos}`;
    86вҶ’      return { kind: "multi", stmts: [
    87вҶ’        { kind: "let", name: tmp, mutable: false, init },
    88вҶ’        ...names.map((n, i) => ({
    89вҶ’          kind: "let" as const, name: n, mutable,
    90вҶ’          init: { kind: "index" as const, object: { kind: "ident" as const, name: tmp }, index: { kind: "number" as const, value: i } as Expr } as Expr,
    91вҶ’        }))
    92вҶ’      ]};
    93вҶ’    }
    94вҶ’
    95вҶ’    const name = expect(T.Ident, "Expected variable name").value;
    96вҶ’    let init: Expr | null = null;
    97вҶ’    if (match(T.Assign)) init = parseExpr();
    98вҶ’    match(T.Semicolon);
    99вҶ’    return { kind: "let", name, mutable, init };
   100вҶ’  }
   101вҶ’
   102вҶ’  function parseFnStmt(): Stmt {
   103вҶ’    advance(); // fn
   104вҶ’    const name = expect(T.Ident, "Expected function name").value;
   105вҶ’    expect(T.LParen);
   106вҶ’    const params = parseParams();
   107вҶ’    expect(T.RParen);
   108вҶ’    // Phase 6: Parse capability annotations [allow(...), limit(...)]
   109вҶ’    const annotations = parseAnnotations();
   110вҶ’    // Skip return type annotation if present: -> Type
   111вҶ’    if (match(T.Arrow)) {
   112вҶ’      // Skip the return type - consume tokens until we hit opening brace
   113вҶ’      let depth = 0;
   114вҶ’      while (!at(T.LBrace) && !at(T.EOF)) {
   115вҶ’        const t = advance();
   116вҶ’        if (t.type === T.LBracket) depth++;
   117вҶ’        if (t.type === T.RBracket) depth--;
   118вҶ’        if (depth < 0) break;
   119вҶ’      }
   120вҶ’    }
   121вҶ’    expect(T.LBrace);
   122вҶ’    const body = parseBody();
   123вҶ’    expect(T.RBrace);
   124вҶ’    return { kind: "fn", name, params, body, annotations };
   125вҶ’  }
   126вҶ’
   127вҶ’  function parseReturn(): Stmt {
   128вҶ’    advance(); // return
   129вҶ’    let value: Expr | null = null;
   130вҶ’    if (!at(T.Semicolon) && !at(T.RBrace) && !at(T.EOF)) value = parseExpr();
   131вҶ’    match(T.Semicolon);
   132вҶ’    return { kind: "return", value };
   133вҶ’  }
   134вҶ’
   135вҶ’  function parseIf(): Stmt {
   136вҶ’    advance(); // if
   137вҶ’
   138вҶ’    // Check for if let pattern
   139вҶ’    if (at(T.Let)) {
   140вҶ’      return parseIfLet();
   141вҶ’    }
   142вҶ’
   143вҶ’    const cond = parseExpr();
   144вҶ’    expect(T.LBrace);
   145вҶ’    const then = parseBody();
   146вҶ’    expect(T.RBrace);
   147вҶ’    let else_: Stmt[] | null = null;
   148вҶ’    if (match(T.Else)) {
   149вҶ’      if (at(T.If)) {
   150вҶ’        else_ = [parseIf()];
   151вҶ’      } else {
   152вҶ’        expect(T.LBrace);
   153вҶ’        else_ = parseBody();
   154вҶ’        expect(T.RBrace);
   155вҶ’      }
   156вҶ’    }
   157вҶ’    return { kind: "if", cond, then, else: else_ };
   158вҶ’  }
   159вҶ’
   160вҶ’  function parseIfLet(): Stmt {
   161вҶ’    advance(); // let
   162вҶ’    const pattern = parseOr(); // Use parseOr to avoid consuming the = operator
   163вҶ’    expect(T.Assign);
   164вҶ’    const value = parseOr(); // Use parseOr for consistency
   165вҶ’    expect(T.LBrace);
   166вҶ’    const body = parseBody();
   167вҶ’    expect(T.RBrace);
   168вҶ’
   169вҶ’    let else_: Stmt[] | undefined;
   170вҶ’    if (match(T.Else)) {
   171вҶ’      if (at(T.LBrace)) {
   172вҶ’        expect(T.LBrace);
   173вҶ’        else_ = parseBody();
   174вҶ’        expect(T.RBrace);
   175вҶ’      } else if (at(T.If)) {
   176вҶ’        // else if pattern
   177вҶ’        else_ = [parseIf()];
   178вҶ’      }
   179вҶ’    }
   180вҶ’
   181вҶ’    return { kind: "if-let", pattern, value, body, else: else_ };
   182вҶ’  }
   183вҶ’
   184вҶ’  /**
   185вҶ’   * [v3.1] Parse if as an expression
   186вҶ’   *
   187вҶ’   * Supports: let x = if condition { value1 } else { value2 };
   188вҶ’   *
   189вҶ’   * Key difference from parseIf():
   190вҶ’   * - Must have else clause (to ensure all paths return a value)
   191вҶ’   * - Body can contain expressions (parsed as statements with implicit return)
   192вҶ’   * - Result is an Expr, not a Stmt
   193вҶ’   */
   194вҶ’  function parseIfExpr(): Expr {
