   376вҶ’
   377вҶ’        // Execute body
   378вҶ’        compileStmts(s.body);
   379вҶ’
   380вҶ’        const skipElse = currentPos();
   381вҶ’        emitArg(Op.Jump, 0);
   382вҶ’
   383вҶ’        // Execute else (if exists)
   384вҶ’        patchJump(skipBody);
   385вҶ’        if (s.else) {
   386вҶ’          compileStmts(s.else);
   387вҶ’        }
   388вҶ’
   389вҶ’        patchJump(skipElse);
   390вҶ’        break;
   391вҶ’      }
   392вҶ’      case "while-let": {
   393вҶ’        // While let: repeat while pattern matches
   394вҶ’        const loopStart = currentPos();
   395вҶ’
   396вҶ’        // Evaluate value
