   404вҶ’        emit(Op.Eq);
   405вҶ’
   406вҶ’        const exit = currentPos();
   407вҶ’        emitArg(Op.JumpIfFalse, 0);
   408вҶ’
   409вҶ’        // Execute body
   410вҶ’        compileStmts(s.body);
   411вҶ’
   412вҶ’        // Loop back
   413вҶ’        emitArg(Op.Jump, loopStart);
   414вҶ’
   415вҶ’        patchJump(exit);
   416вҶ’        break;
   417вҶ’      }
   418вҶ’    }
   419вҶ’  }
