   421вҶ’  function compileFnBody(name: string, params: string[], body: Stmt[], annotations: any[] = []) {
   422вҶ’    // Phase 6: Extract capabilities from allow-kind annotations
   423вҶ’    const capabilities = annotations
   424вҶ’      .filter((a: any) => a.kind === "allow")
   425вҶ’      .map((a: any) => ({ cap: a.cap, arg: a.arg }));
   426вҶ’
   427вҶ’    // Phase 6.4: Extract resource limits from limit-kind annotations
   428вҶ’    const resourceLimits: Record<string, number> = {};
   429вҶ’    annotations
   430вҶ’      .filter((a: any) => a.kind === "limit")
   431вҶ’      .forEach((a: any) => {
   432вҶ’        resourceLimits[a.resource] = a.value;
   433вҶ’      });
   434вҶ’
   435вҶ’    const jumpOver = currentPos(); emitArg(Op.Jump, 0);
   436вҶ’    const fnAddr = currentPos();
   437вҶ’    scopes.push({ locals: [], depth: 1, upvalues: [] });
   438вҶ’    for (const p of params) declareLocal(p);
   439вҶ’    // Compile body as expression: last stmt should leave value on stack
   440вҶ’    if (body.length === 0) {
   441вҶ’      emitArg(Op.Const, addConst({ tag: "null" }));
