   443вҶ’      compileStmtsAsExpr(body);
   444вҶ’    }
   445вҶ’    emit(Op.Return);
   446вҶ’    const fnScope = scopes.pop()!;
   447вҶ’    patchJump(jumpOver);
   448вҶ’
   449вҶ’    if (fnScope.upvalues.length > 0) {
   450вҶ’      for (const uv of fnScope.upvalues) {
   451вҶ’        if (uv.isLocal) emitArg(Op.Load, uv.index);
   452вҶ’        else emitArg(Op.LoadFree, uv.index);
   453вҶ’      }
   454вҶ’      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [], capabilities, resourceLimits }));
   455вҶ’      emitArg(Op.NewClosure, fnScope.upvalues.length);
   456вҶ’    } else {
   457вҶ’      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [], capabilities, resourceLimits }));
   458вҶ’    }
