   468вҶ’        const local = resolveLocal(e.name);
   469вҶ’        if (local !== -1) { emitArg(Op.Load, local); break; }
   470вҶ’        const upval = resolveUpvalue(e.name);
   471вҶ’        if (upval !== -1) { emitArg(Op.LoadFree, upval); break; }
