   478вҶ’          const l = e.left.value, r = e.right.value;
   479вҶ’          let result: Value | null = null;
   480вҶ’          if (e.op === "+") result = { tag: "num", val: l + r };
   481вҶ’          else if (e.op === "-") result = { tag: "num", val: l - r };
   482вҶ’          else if (e.op === "*") result = { tag: "num", val: l * r };
   483вҶ’          else if (e.op === "/" && r !== 0) result = { tag: "num", val: l / r };
   484вҶ’          else if (e.op === "%") result = { tag: "num", val: l % r };
   485вҶ’          else if (e.op === "==") result = { tag: "bool", val: l === r };
   486вҶ’          else if (e.op === "!=") result = { tag: "bool", val: l !== r };
   487вҶ’          else if (e.op === "<") result = { tag: "bool", val: l < r };
   488вҶ’          else if (e.op === ">") result = { tag: "bool", val: l > r };
   489вҶ’          else if (e.op === "<=") result = { tag: "bool", val: l <= r };
