   495вҶ’          emitArg(Op.Const, addConst({ tag: "str", val: e.left.value + e.right.value }));
   496вҶ’          break;
   497вҶ’        }
   498вҶ’
   499вҶ’        // л‘җ н”јм—°мӮ°мһҗ м»ҙнҢҢмқј
   500вҶ’        compileExpr(e.left);
   501вҶ’        compileExpr(e.right);
   502вҶ’
   503вҶ’        // Phase 5.5: Typed Op м„ нғқ
   504вҶ’        const leftType = inferExprType(e.left);
   505вҶ’        const rightType = inferExprType(e.right);
   506вҶ’
   507вҶ’        // num + num вҶ’ Typed Arithmetic
   508вҶ’        if (leftType === "num" && rightType === "num") {
   509вҶ’          const typedArith: Record<string, Op> = {
   510вҶ’            "+": Op.AddNum, "-": Op.SubNum, "*": Op.MulNum,
   511вҶ’            "/": Op.DivNum, "%": Op.ModNum,
   512вҶ’            "==": Op.EqNum, "<": Op.LtNum, ">": Op.GtNum,
   513вҶ’            "<=": Op.LteNum, ">=": Op.GteNum,
   514вҶ’          };
