   575вҶ’          compileExpr(value);
   576вҶ’        }
   577вҶ’        emitArg(Op.NewObject, e.entries.length);
   578вҶ’        break;
   579вҶ’      }
   580вҶ’      case "index": {
   581вҶ’        compileExpr(e.object);
   582вҶ’        compileExpr(e.index);
   583вҶ’        emit(Op.Index);
   584вҶ’        break;
   585вҶ’      }
   586вҶ’      case "member": {
   587вҶ’        compileExpr(e.object);
   588вҶ’        emitArg(Op.GetProp, addConst({ tag: "str", val: e.property }));
