   597вҶ’        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   598вҶ’        compileExpr(e.then);
   599вҶ’        const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   600вҶ’        patchJump(jumpFalse);
   601вҶ’        compileExpr(e.else);
   602вҶ’        patchJump(jumpEnd);
   603вҶ’        break;
   604вҶ’      }
   605вҶ’      case "if": {
   606вҶ’        // If-expression: if cond { then_block } else { else_block }
   607вҶ’        // Both blocks must produce a value on the stack (don't pop last expr)
