   609вҶ’        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   610вҶ’        compileStmtsAsExpr(e.then);
   611вҶ’        const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   612вҶ’        patchJump(jumpFalse);
   613вҶ’        compileStmtsAsExpr(e.else);
   614вҶ’        patchJump(jumpEnd);
