   650вҶ’            if (arm.guard) {
   651вҶ’              // Even wildcard can have guard
   652вҶ’              compileExpr(arm.guard);
   653вҶ’              const skip = currentPos();
   654вҶ’              emitArg(Op.JumpIfFalse, 0);
   655вҶ’              compileStmtsAsExpr(arm.body);
   656вҶ’              endPatches.push(currentPos());
   657вҶ’              emitArg(Op.Jump, 0);
   658вҶ’              patchJump(skip);
