   670вҶ’      }
   671вҶ’    }
   672вҶ’  }
   673вҶ’
   674вҶ’  compileStmts(program.stmts);
   675вҶ’  emit(Op.Halt);
   676вҶ’  return chunk;
   677вҶ’}
