    51вҶ’    }
    52вҶ’
    53вҶ’    // Second pass: н•ЁмҲҳ ліёл¬ё л°Ҹ лӢӨлҘё лӘ…л №л¬ё кІҖмӮ¬
    54вҶ’    for (const stmt of program.stmts) {
    55вҶ’      this.checkStmt(stmt)
    56вҶ’    }
    57вҶ’
    58вҶ’    return {
    59вҶ’      success: this.errors.length === 0,
    60вҶ’      errors: this.errors,
    61вҶ’      types: new Map(this.env),
    62вҶ’    }
    63вҶ’  }
    64вҶ’
    65вҶ’  /**
    66вҶ’   * мҲҳм§‘лҗң return нғҖмһ…л“ӨлЎңл¶Җн„° н•ЁмҲҳмқҳ л°ҳнҷҳ нғҖмһ… м¶”лЎ 
    67вҶ’   */
    68вҶ’  private inferReturnType(types: Type[]): Type {
    69вҶ’    if (types.length === 0) return BUILTIN_TYPES.UNKNOWN
    70вҶ’    const first = types[0]
    71вҶ’    if (types.every(t => JSON.stringify(t) === JSON.stringify(first)))
    72вҶ’      return first
    73вҶ’    return BUILTIN_TYPES.UNKNOWN
    74вҶ’  }
    75вҶ’
    76вҶ’  /**
    77вҶ’   * н•ЁмҲҳ нғҖмһ… л“ұлЎқ
    78вҶ’   */
    79вҶ’  private registerFunctionType(stmt: Stmt): void {
    80вҶ’    if (stmt.kind === "fn") {
    81вҶ’      const fnStmt = stmt as any
    82вҶ’      const paramTypes: Type[] = (fnStmt.params || []).map(() => ({
    83вҶ’        kind: "primitive" as const,
    84вҶ’        type: PrimitiveType.UNKNOWN,
    85вҶ’      }))
    86вҶ’
    87вҶ’      const returnType: Type = {
    88вҶ’        kind: "primitive",
    89вҶ’        type: PrimitiveType.UNKNOWN,
    90вҶ’      }
    91вҶ’
    92вҶ’      // Phase 6: annotations вҶ’ capabilities ліҖнҷҳ
    93вҶ’      const capabilities: Capability[] = (fnStmt.annotations || [])
    94вҶ’        .filter((a: any) => a.kind === "allow")
    95вҶ’        .map((a: any) => ({ cap: a.cap, arg: a.arg }))
    96вҶ’
    97вҶ’      const fnType: Type = {
    98вҶ’        kind: "fn",
    99вҶ’        paramTypes,
   100вҶ’        returnType,
   101вҶ’        capabilities,
   102вҶ’      }
   103вҶ’
   104вҶ’      this.functionTypes.set(fnStmt.name, fnType)
   105вҶ’    }
   106вҶ’  }
   107вҶ’
   108вҶ’  /**
   109вҶ’   * лӘ…л №л¬ё нғҖмһ… кІҖмӮ¬
   110вҶ’   */
   111вҶ’  private checkStmt(stmt: Stmt): void {
   112вҶ’    switch (stmt.kind) {
   113вҶ’      case "print": {
   114вҶ’        const printStmt = stmt as any
   115вҶ’        this.checkExpr(printStmt.expr)
   116вҶ’        break
   117вҶ’      }
   118вҶ’
   119вҶ’      case "expr": {
   120вҶ’        const exprStmt = stmt as any
   121вҶ’        this.checkExpr(exprStmt.expr)
   122вҶ’        break
   123вҶ’      }
   124вҶ’
   125вҶ’      case "let": {
   126вҶ’        const letStmt = stmt as any
   127вҶ’        if (letStmt.init) {
   128вҶ’          const valueType = this.checkExpr(letStmt.init)
   129вҶ’          this.env.set(letStmt.name, valueType)
   130вҶ’        } else {
   131вҶ’          this.env.set(letStmt.name, BUILTIN_TYPES.UNKNOWN)
   132вҶ’        }
   133вҶ’        break
   134вҶ’      }
   135вҶ’
   136вҶ’      case "fn": {
   137вҶ’        const fnStmt = stmt as any
   138вҶ’        const savedEnv = new Map(this.env)
   139вҶ’        const savedReturnTypes = this.currentFunctionReturnTypes
   140вҶ’        const savedCapabilities = this.currentCapabilities
   141вҶ’
   142вҶ’        // Phase 6: нҳ„мһ¬ н•ЁмҲҳмқҳ м„ м–ё capabilityлЎң м»Ён…ҚмҠӨнҠё м„Өм •
   143вҶ’        const fnType = this.functionTypes.get(fnStmt.name)
   144вҶ’        this.currentCapabilities = fnType?.kind === "fn"
   145вҶ’          ? (fnType.capabilities ?? [])
   146вҶ’          : []
   147вҶ’
   148вҶ’        this.currentFunctionReturnTypes = []
   149вҶ’
   150вҶ’        // нҢҢлқјлҜён„°лҘј нҷҳкІҪм—җ м¶”к°Җ
   151вҶ’        for (const param of fnStmt.params || []) {
   152вҶ’          this.env.set(param, {
   153вҶ’            kind: "primitive",
   154вҶ’            type: PrimitiveType.UNKNOWN,
   155вҶ’          })
   156вҶ’        }
   157вҶ’
   158вҶ’        // н•ЁмҲҳ ліёл¬ё кІҖмӮ¬
   159вҶ’        for (const s of fnStmt.body || []) {
   160вҶ’          this.checkStmt(s)
   161вҶ’        }
   162вҶ’
   163вҶ’        // return нғҖмһ… м¶”лЎ  нӣ„ functionTypes к°ұмӢ 
   164вҶ’        const inferredReturn = this.inferReturnType(
   165вҶ’          this.currentFunctionReturnTypes
   166вҶ’        )
   167вҶ’        const existingFnType = this.functionTypes.get(fnStmt.name)
   168вҶ’        if (existingFnType && existingFnType.kind === "fn") {
   169вҶ’          this.functionTypes.set(fnStmt.name, {
   170вҶ’            kind: "fn",
   171вҶ’            paramTypes: existingFnType.paramTypes,
   172вҶ’            returnType: inferredReturn,
   173вҶ’            capabilities: existingFnType.capabilities, // Phase 6: ліҙмЎҙ
   174вҶ’          })
   175вҶ’        }
   176вҶ’
   177вҶ’        this.currentCapabilities = savedCapabilities
   178вҶ’        this.currentFunctionReturnTypes = savedReturnTypes
   179вҶ’        this.env = savedEnv
   180вҶ’        break
   181вҶ’      }
   182вҶ’
   183вҶ’      case "if": {
   184вҶ’        const ifStmt = stmt as any
   185вҶ’        this.checkExpr(ifStmt.cond)
   186вҶ’        for (const s of ifStmt.then || []) {
   187вҶ’          this.checkStmt(s)
   188вҶ’        }
   189вҶ’        if (ifStmt.else) {
   190вҶ’          for (const s of ifStmt.else) {
   191вҶ’            this.checkStmt(s)
   192вҶ’          }
   193вҶ’        }
   194вҶ’        break
   195вҶ’      }
   196вҶ’
   197вҶ’      case "for": {
   198вҶ’        const forStmt = stmt as any
   199вҶ’        this.checkExpr(forStmt.iter)
   200вҶ’        // лЈЁн”„ ліҖмҲҳлҘј нҷҳкІҪм—җ м¶”к°Җ
   201вҶ’        this.env.set(forStmt.name, BUILTIN_TYPES.UNKNOWN)
   202вҶ’        for (const s of forStmt.body || []) {
   203вҶ’          this.checkStmt(s)
   204вҶ’        }
   205вҶ’        break
   206вҶ’      }
   207вҶ’
   208вҶ’      case "while": {
   209вҶ’        const whileStmt = stmt as any
   210вҶ’        this.checkExpr(whileStmt.cond)
   211вҶ’        for (const s of whileStmt.body || []) {
   212вҶ’          this.checkStmt(s)
   213вҶ’        }
   214вҶ’        break
   215вҶ’      }
   216вҶ’
   217вҶ’      case "return": {
   218вҶ’        const returnStmt = stmt as any
   219вҶ’        if (returnStmt.value) {
   220вҶ’          const retType = this.checkExpr(returnStmt.value)
   221вҶ’          this.currentFunctionReturnTypes.push(retType)
   222вҶ’        }
   223вҶ’        break
   224вҶ’      }
   225вҶ’
   226вҶ’      case "block": {
   227вҶ’        const blockStmt = stmt as any
   228вҶ’        for (const s of blockStmt.body || []) {
   229вҶ’          this.checkStmt(s)
   230вҶ’        }
   231вҶ’        break
   232вҶ’      }
   233вҶ’
   234вҶ’      case "try": {
   235вҶ’        const tryStmt = stmt as any
   236вҶ’        for (const s of tryStmt.body || []) {
   237вҶ’          this.checkStmt(s)
   238вҶ’        }
   239вҶ’        if (tryStmt.catchVar) {
   240вҶ’          this.env.set(tryStmt.catchVar, BUILTIN_TYPES.UNKNOWN)
   241вҶ’        }
   242вҶ’        for (const s of tryStmt.catchBody || []) {
   243вҶ’          this.checkStmt(s)
   244вҶ’        }
   245вҶ’        for (const s of tryStmt.finallyBody || []) {
   246вҶ’          this.checkStmt(s)
   247вҶ’        }
   248вҶ’        break
   249вҶ’      }
   250вҶ’
   251вҶ’      case "throw": {
   252вҶ’        const throwStmt = stmt as any
   253вҶ’        this.checkExpr(throwStmt.expr)
   254вҶ’        break
   255вҶ’      }
   256вҶ’
   257вҶ’      case "if-let": {
   258вҶ’        const ifLetStmt = stmt as any
   259вҶ’        this.checkExpr(ifLetStmt.value)
   260вҶ’        // нҢЁн„ҙ л°”мқёл”©
   261вҶ’        if (ifLetStmt.pattern.kind === "ident") {
   262вҶ’          this.env.set(ifLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   263вҶ’        }
   264вҶ’        for (const s of ifLetStmt.body || []) {
   265вҶ’          this.checkStmt(s)
   266вҶ’        }
   267вҶ’        if (ifLetStmt.else) {
   268вҶ’          for (const s of ifLetStmt.else) {
   269вҶ’            this.checkStmt(s)
   270вҶ’          }
   271вҶ’        }
   272вҶ’        break
   273вҶ’      }
   274вҶ’
   275вҶ’      case "while-let": {
   276вҶ’        const whileLetStmt = stmt as any
   277вҶ’        this.checkExpr(whileLetStmt.value)
   278вҶ’        if (whileLetStmt.pattern.kind === "ident") {
   279вҶ’          this.env.set(whileLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   280вҶ’        }
   281вҶ’        for (const s of whileLetStmt.body || []) {
   282вҶ’          this.checkStmt(s)
   283вҶ’        }
   284вҶ’        break
   285вҶ’      }
   286вҶ’
   287вҶ’      case "match": {
   288вҶ’        const matchStmt = stmt as any
   289вҶ’        this.checkExpr(matchStmt.subject)
   290вҶ’        for (const arm of matchStmt.arms || []) {
   291вҶ’          if (arm.pattern) {
   292вҶ’            this.checkExpr(arm.pattern)
   293вҶ’          }
   294вҶ’          if (arm.guard) {
   295вҶ’            this.checkExpr(arm.guard)
   296вҶ’          }
   297вҶ’          for (const s of arm.body || []) {
   298вҶ’            this.checkStmt(s)
   299вҶ’          }
   300вҶ’        }
   301вҶ’        break
   302вҶ’      }
   303вҶ’    }
   304вҶ’  }
   305вҶ’
   306вҶ’  /**
   307вҶ’   * н‘ңнҳ„мӢқ нғҖмһ… кІҖмӮ¬
   308вҶ’   */
   309вҶ’  public checkExpr(expr: Expr): Type {
   310вҶ’    switch (expr.kind) {
   311вҶ’      case "number":
   312вҶ’        return { kind: "primitive", type: PrimitiveType.NUM }
   313вҶ’
   314вҶ’      case "string":
   315вҶ’        return { kind: "primitive", type: PrimitiveType.STR }
   316вҶ’
   317вҶ’      case "bool":
   318вҶ’        return { kind: "primitive", type: PrimitiveType.BOOL }
   319вҶ’
   320вҶ’      case "null":
   321вҶ’        return { kind: "primitive", type: PrimitiveType.NULL }
   322вҶ’
   323вҶ’      case "ident": {
   324вҶ’        const identExpr = expr as any
   325вҶ’        const type = this.env.get(identExpr.name)
   326вҶ’        if (!type) {
   327вҶ’          this.addError(
   328вҶ’            `Undefined variable '${identExpr.name}'`,
   329вҶ’            undefined,
   330вҶ’            undefined
   331вҶ’          )
   332вҶ’          return BUILTIN_TYPES.UNKNOWN
   333вҶ’        }
   334вҶ’        return type
   335вҶ’      }
   336вҶ’
   337вҶ’      case "assign": {
   338вҶ’        const assignExpr = expr as any
   339вҶ’        const valueType = this.checkExpr(assignExpr.value)
   340вҶ’
   341вҶ’        // targetмқҙ identмқё кІҪмҡ° н• лӢ№
   342вҶ’        if (assignExpr.target.kind === "ident") {
   343вҶ’          this.env.set(assignExpr.target.name, valueType)
   344вҶ’        }
   345вҶ’        return valueType
   346вҶ’      }
   347вҶ’
   348вҶ’      case "binary": {
   349вҶ’        const binExpr = expr as any
   350вҶ’        const leftType = this.checkExpr(binExpr.left)
   351вҶ’        const rightType = this.checkExpr(binExpr.right)
   352вҶ’
   353вҶ’        // нғҖмһ… нҳёнҷҳм„ұ кІҖмӮ¬
   354вҶ’        const resultType = getOperationResultType(
   355вҶ’          binExpr.op,
   356вҶ’          leftType,
   357вҶ’          rightType
   358вҶ’        )
   359вҶ’
   360вҶ’        // Add м—°мӮ° кІҖмҰқ
   361вҶ’        if (binExpr.op === "+" || binExpr.op === "Add") {
   362вҶ’          if (leftType.kind === "primitive" && rightType.kind === "primitive") {
   363вҶ’            const left = leftType.type
   364вҶ’            const right = rightType.type
   365вҶ’
   366вҶ’            if (
   367вҶ’              !(
   368вҶ’                (left === PrimitiveType.NUM && right === PrimitiveType.NUM) ||
   369вҶ’                (left === PrimitiveType.STR || right === PrimitiveType.STR) ||
   370вҶ’                (left === PrimitiveType.UNKNOWN ||
   371вҶ’                  right === PrimitiveType.UNKNOWN)
   372вҶ’              )
   373вҶ’            ) {
   374вҶ’              this.addError(
   375вҶ’                `Cannot add ${typeToString(leftType)} and ${typeToString(rightType)}`,
   376вҶ’                undefined,
   377вҶ’                undefined,
   378вҶ’                undefined,
   379вҶ’                leftType,
   380вҶ’                rightType
   381вҶ’              )
   382вҶ’            }
   383вҶ’          }
   384вҶ’        }
   385вҶ’
   386вҶ’        return resultType
   387вҶ’      }
   388вҶ’
   389вҶ’      case "unary": {
   390вҶ’        const unaryExpr = expr as any
   391вҶ’        const operandType = this.checkExpr(unaryExpr.expr)
   392вҶ’
   393вҶ’        if (unaryExpr.op === "!") {
   394вҶ’          if (
   395вҶ’            operandType.kind !== "primitive" ||
   396вҶ’            operandType.type !== PrimitiveType.BOOL
   397вҶ’          ) {
   398вҶ’            this.addError(
   399вҶ’              `Cannot apply ! to ${typeToString(operandType)}`,
   400вҶ’              undefined,
   401вҶ’              undefined
   402вҶ’            )
   403вҶ’          }
   404вҶ’          return BUILTIN_TYPES.BOOL
   405вҶ’        }
   406вҶ’
   407вҶ’        if (unaryExpr.op === "-") {
   408вҶ’          if (
   409вҶ’            operandType.kind !== "primitive" ||
   410вҶ’            operandType.type !== PrimitiveType.NUM
   411вҶ’          ) {
   412вҶ’            this.addError(
   413вҶ’              `Cannot negate ${typeToString(operandType)}`,
   414вҶ’              undefined,
   415вҶ’              undefined
   416вҶ’            )
   417вҶ’          }
   418вҶ’          return BUILTIN_TYPES.NUM
   419вҶ’        }
   420вҶ’
   421вҶ’        return operandType
   422вҶ’      }
   423вҶ’
   424вҶ’      case "call": {
   425вҶ’        const callExpr = expr as any
   426вҶ’
   427вҶ’        // calleeм—җм„ң н•ЁмҲҳ мқҙлҰ„ м¶”м¶ң
   428вҶ’        let fnName = ""
   429вҶ’        if (callExpr.callee.kind === "ident") {
   430вҶ’          fnName = callExpr.callee.name
   431вҶ’        }
   432вҶ’
   433вҶ’        // Phase 6: Built-in н•ЁмҲҳ required capability кІҖмӮ¬
   434вҶ’        const builtinRequired = this.BUILTIN_REQUIRED_CAPABILITIES.get(fnName)
   435вҶ’        if (builtinRequired) {
   436вҶ’          const callerHas = this.currentCapabilities.some(c => c.cap === builtinRequired)
   437вҶ’          if (!callerHas) {
   438вҶ’            this.addError(
   439вҶ’              `'${fnName}' requires capability '${builtinRequired}', not declared`,
   440вҶ’              undefined,
   441вҶ’              undefined
   442вҶ’            )
   443вҶ’          }
   444вҶ’        }
   445вҶ’
   446вҶ’        const fnType = this.functionTypes.get(fnName)
   447вҶ’
   448вҶ’        if (!fnType) {
   449вҶ’          this.addError(
   450вҶ’            `Undefined function '${fnName}'`,
   451вҶ’            undefined,
   452вҶ’            undefined
   453вҶ’          )
   454вҶ’          return BUILTIN_TYPES.UNKNOWN
   455вҶ’        }
   456вҶ’
   457вҶ’        if (fnType.kind === "fn") {
   458вҶ’          // мқёмһҗ к°ңмҲҳ нҷ•мқё
   459вҶ’          if ((callExpr.args || []).length !== fnType.paramTypes.length) {
   460вҶ’            this.addError(
   461вҶ’              `Function '${fnName}' expects ${fnType.paramTypes.length} arguments, got ${(callExpr.args || []).length}`,
   462вҶ’              undefined,
   463вҶ’              undefined
   464вҶ’            )
   465вҶ’          }
   466вҶ’
   467вҶ’          // мқёмһҗ нғҖмһ… кІҖмӮ¬
   468вҶ’          for (let i = 0; i < (callExpr.args || []).length; i++) {
   469вҶ’            const argType = this.checkExpr(callExpr.args[i])
   470вҶ’            const paramType = fnType.paramTypes[i] || BUILTIN_TYPES.UNKNOWN
   471вҶ’
   472вҶ’            if (!typesCompatible(argType, paramType)) {
   473вҶ’              this.addError(
   474вҶ’                `Argument ${i} of '${fnName}': expected ${typeToString(paramType)}, got ${typeToString(argType)}`,
   475вҶ’                undefined,
   476вҶ’                undefined,
   477вҶ’                undefined,
   478вҶ’                paramType,
   479вҶ’                argType
   480вҶ’              )
   481вҶ’            }
   482вҶ’          }
   483вҶ’
   484вҶ’          // Phase 6: Capability Propagation кІҖмҰқ
   485вҶ’          // Strict: callee.capabilities вҠҶ caller.capabilities
   486вҶ’          if (fnType.capabilities && fnType.capabilities.length > 0) {
   487вҶ’            for (const required of fnType.capabilities) {
   488вҶ’              const callerHas = this.currentCapabilities.some(
   489вҶ’                c => c.cap === required.cap && this.capabilityCovers(c, required)
   490вҶ’              )
   491вҶ’              if (!callerHas) {
   492вҶ’                this.addError(
   493вҶ’                  `Call to '${fnName}' requires capability '${required.cap}' ` +
   494вҶ’                  `${required.arg ? `(${required.arg})` : ""}, ` +
   495вҶ’                  `but caller does not declare it`,
   496вҶ’                  undefined,
   497вҶ’                  undefined
   498вҶ’                )
   499вҶ’              }
   500вҶ’            }
   501вҶ’          }
   502вҶ’
   503вҶ’          return fnType.returnType
   504вҶ’        }
   505вҶ’
   506вҶ’        return BUILTIN_TYPES.UNKNOWN
   507вҶ’      }
   508вҶ’
   509вҶ’      case "array": {
   510вҶ’        const arrayExpr = expr as any
   511вҶ’        if ((arrayExpr.elements || []).length === 0) {
   512вҶ’          return {
   513вҶ’            kind: "array",
   514вҶ’            elementType: BUILTIN_TYPES.UNKNOWN,
   515вҶ’          }
   516вҶ’        }
   517вҶ’
   518вҶ’        const elementTypes = (arrayExpr.elements || []).map((e: any) =>
   519вҶ’          this.checkExpr(e)
   520вҶ’        )
   521вҶ’
   522вҶ’        // лӘЁл“  мҡ”мҶҢ нғҖмһ…мқҙ к°ҷмқҖм§Җ нҷ•мқё
   523вҶ’        const firstType = elementTypes[0]
   524вҶ’        for (let i = 1; i < elementTypes.length; i++) {
   525вҶ’          if (!typesCompatible(elementTypes[i], firstType)) {
   526вҶ’            this.addError(
   527вҶ’              `Array elements have inconsistent types: ${typeToString(firstType)} and ${typeToString(elementTypes[i])}`,
   528вҶ’              undefined,
   529вҶ’              undefined
   530вҶ’            )
   531вҶ’          }
   532вҶ’        }
   533вҶ’
   534вҶ’        return {
   535вҶ’          kind: "array",
   536вҶ’          elementType: firstType,
   537вҶ’        }
   538вҶ’      }
   539вҶ’
   540вҶ’      case "index": {
   541вҶ’        const indexExpr = expr as any
   542вҶ’        const objectType = this.checkExpr(indexExpr.object)
   543вҶ’        this.checkExpr(indexExpr.index)
   544вҶ’
   545вҶ’        if (objectType.kind === "array") {
   546вҶ’          return objectType.elementType
   547вҶ’        }
   548вҶ’        return BUILTIN_TYPES.UNKNOWN
   549вҶ’      }
   550вҶ’
   551вҶ’      case "member": {
   552вҶ’        const memberExpr = expr as any
   553вҶ’        const objectType = this.checkExpr(memberExpr.object)
   554вҶ’
   555вҶ’        if (objectType.kind === "object") {
   556вҶ’          const propType = objectType.properties.get(memberExpr.property)
   557вҶ’          return propType || BUILTIN_TYPES.UNKNOWN
   558вҶ’        }
   559вҶ’        return BUILTIN_TYPES.UNKNOWN
   560вҶ’      }
   561вҶ’
   562вҶ’      case "object": {
   563вҶ’        const objExpr = expr as any
   564вҶ’        const properties = new Map<string, Type>()
   565вҶ’
   566вҶ’        for (const entry of objExpr.entries || []) {
   567вҶ’          properties.set(entry.key, this.checkExpr(entry.value))
   568вҶ’        }
   569вҶ’
   570вҶ’        return {
   571вҶ’          kind: "object",
   572вҶ’          properties,
   573вҶ’        }
   574вҶ’      }
   575вҶ’
   576вҶ’      case "fn": {
   577вҶ’        const fnExpr = expr as any
   578вҶ’        const savedEnv = new Map(this.env)
   579вҶ’        const savedReturnTypes = this.currentFunctionReturnTypes
   580вҶ’
   581вҶ’        this.currentFunctionReturnTypes = []
   582вҶ’
   583вҶ’        // нҢҢлқјлҜён„°лҘј нҷҳкІҪм—җ м¶”к°Җ
   584вҶ’        for (const param of fnExpr.params || []) {
   585вҶ’          this.env.set(param, {
   586вҶ’            kind: "primitive",
   587вҶ’            type: PrimitiveType.UNKNOWN,
   588вҶ’          })
   589вҶ’        }
   590вҶ’
   591вҶ’        // н•ЁмҲҳ ліёл¬ё кІҖмӮ¬
   592вҶ’        for (const stmt of fnExpr.body || []) {
   593вҶ’          this.checkStmt(stmt)
   594вҶ’        }
   595вҶ’
   596вҶ’        const inferredReturn = this.inferReturnType(
   597вҶ’          this.currentFunctionReturnTypes
   598вҶ’        )
   599вҶ’        const paramTypes: Type[] = (fnExpr.params || []).map(() => ({
   600вҶ’          kind: "primitive" as const,
   601вҶ’          type: PrimitiveType.UNKNOWN,
   602вҶ’        }))
   603вҶ’
   604вҶ’        this.currentFunctionReturnTypes = savedReturnTypes
   605вҶ’        this.env = savedEnv
   606вҶ’
   607вҶ’        return {
   608вҶ’          kind: "fn",
   609вҶ’          paramTypes,
   610вҶ’          returnType: inferredReturn,
   611вҶ’        }
   612вҶ’      }
   613вҶ’
   614вҶ’      case "ternary": {
   615вҶ’        const ternaryExpr = expr as any
   616вҶ’        this.checkExpr(ternaryExpr.cond)
   617вҶ’        const thenType = this.checkExpr(ternaryExpr.then)
   618вҶ’        const elseType = this.checkExpr(ternaryExpr.else)
   619вҶ’
   620вҶ’        // thenкіј else нғҖмһ…мқҙ нҳёнҷҳ к°ҖлҠҘн•ҙм•ј н•Ё
   621вҶ’        if (!typesCompatible(thenType, elseType)) {
   622вҶ’          this.addError(
   623вҶ’            `Ternary branch types incompatible: ${typeToString(thenType)} vs ${typeToString(elseType)}`,
   624вҶ’            undefined,
   625вҶ’            undefined
   626вҶ’          )
   627вҶ’        }
   628вҶ’
   629вҶ’        return thenType
   630вҶ’      }
   631вҶ’
   632вҶ’      case "if": {
   633вҶ’        const ifExpr = expr as any
   634вҶ’        this.checkExpr(ifExpr.cond)
   635вҶ’        for (const s of ifExpr.then || []) {
   636вҶ’          this.checkStmt(s)
   637вҶ’        }
   638вҶ’        for (const s of ifExpr.else || []) {
   639вҶ’          this.checkStmt(s)
   640вҶ’        }
   641вҶ’        return BUILTIN_TYPES.UNKNOWN
   642вҶ’      }
   643вҶ’
   644вҶ’      case "match": {
   645вҶ’        const matchExpr = expr as any
   646вҶ’        this.checkExpr(matchExpr.subject)
   647вҶ’        for (const arm of matchExpr.arms || []) {
   648вҶ’          if (arm.pattern) {
   649вҶ’            this.checkExpr(arm.pattern)
   650вҶ’          }
   651вҶ’          if (arm.guard) {
   652вҶ’            this.checkExpr(arm.guard)
   653вҶ’          }
   654вҶ’          for (const s of arm.body || []) {
   655вҶ’            this.checkStmt(s)
   656вҶ’          }
   657вҶ’        }
   658вҶ’        return BUILTIN_TYPES.UNKNOWN
   659вҶ’      }
   660вҶ’
   661вҶ’      default:
   662вҶ’        return BUILTIN_TYPES.UNKNOWN
   663вҶ’    }
   664вҶ’  }
   665вҶ’
   666вҶ’  /**
   667вҶ’   * мҳӨлҘҳ м¶”к°Җ
   668вҶ’   */
   669вҶ’  private addError(
   670вҶ’    message: string,
   671вҶ’    line?: number,
   672вҶ’    column?: number,
   673вҶ’    variable?: string,
   674вҶ’    expected?: Type,
   675вҶ’    actual?: Type
   676вҶ’  ): void {
   677вҶ’    this.errors.push({
   678вҶ’      message,
   679вҶ’      line,
   680вҶ’      column,
   681вҶ’      variable,
   682вҶ’      expected,
   683вҶ’      actual,
   684вҶ’    })
   685вҶ’  }
   686вҶ’
   687вҶ’  /**
   688вҶ’   * нҷҳкІҪ мЎ°нҡҢ
   689вҶ’   */
   690вҶ’  public getEnv(): Map<string, Type> {
   691вҶ’    return new Map(this.env)
   692вҶ’  }
   693вҶ’
   694вҶ’  /**
   695вҶ’   * н•ЁмҲҳ нғҖмһ… мЎ°нҡҢ
   696вҶ’   */
   697вҶ’  public getFunctionType(name: string): Type | undefined {
   698вҶ’    return this.functionTypes.get(name)
   699вҶ’  }
   700вҶ’
   701вҶ’  /**
   702вҶ’   * мҳӨлҘҳ к°ңмҲҳ
   703вҶ’   */
   704вҶ’  public getErrorCount(): number {
   705вҶ’    return this.errors.length
   706вҶ’  }
   707вҶ’
   708вҶ’  /**
   709вҶ’   * мҳӨлҘҳ лӘ©лЎқ
   710вҶ’   */
   711вҶ’  public getErrors(): TypeCheckError[] {
   712вҶ’    return [...this.errors]
   713вҶ’  }
   714вҶ’
   715вҶ’  /**
   716вҶ’   * Phase 6: Capability н—¬нҚј н•ЁмҲҳл“Ө
   717вҶ’   */
   718вҶ’  private capabilityCovers(caller: Capability, callee: Capability): boolean {
   719вҶ’    if (caller.cap !== callee.cap) return false
   720вҶ’    if (!callee.arg) return true // calleeк°Җ кІҪлЎң л¬ҙкҙҖн•ҳл©ҙ OK
   721вҶ’    if (!caller.arg) return false
   722вҶ’
   723вҶ’    // Path: /tmp вҶ’ /tmp/file.txt OK, /tmp вҶ’ /etc NG
   724вҶ’    if (caller.cap === "read_file" || caller.cap === "write_file") {
   725вҶ’      return this.pathIsUnder(callee.arg, caller.arg)
   726вҶ’    }
   727вҶ’
   728вҶ’    // Network: api.openai.com вҶ’ api.openai.com OK, *.openai.com вҶ’ sub.openai.com OK
   729вҶ’    if (caller.cap === "network") {
   730вҶ’      return this.hostMatches(callee.arg, caller.arg)
   731вҶ’    }
   732вҶ’
   733вҶ’    return caller.arg === callee.arg
   734вҶ’  }
   735вҶ’
   736вҶ’  private pathIsUnder(target: string, allowedPrefix: string): boolean {
   737вҶ’    // ".." мҰүмӢң кұ°л¶Җ
   738вҶ’    if (target.includes("..")) return false
   739вҶ’    const normalized = target.replace(/\/+/g, "/").replace(/\/$/, "")
   740вҶ’    const prefix = allowedPrefix.replace(/\/+/g, "/").replace(/\/$/, "")
   741вҶ’    return normalized === prefix || normalized.startsWith(prefix + "/")
   742вҶ’  }
   743вҶ’
   744вҶ’  private hostMatches(target: string, pattern: string): boolean {
   745вҶ’    if (pattern === target) return true
   746вҶ’    if (pattern.startsWith("*.")) {
   747вҶ’      const base = pattern.slice(2)
   748вҶ’      return (
   749вҶ’        target.endsWith("." + base) &&
   750вҶ’        !target.slice(0, -base.length - 1).includes(".")
   751вҶ’      )
   752вҶ’    }
   753вҶ’    return false
   754вҶ’  }
   755вҶ’}
