     1вҶ’// Phase 5: нғҖмһ… мӢңмҠӨн…ң кё°ліё м •мқҳ
     2вҶ’
     3вҶ’/**
     4вҶ’ * Primitive нғҖмһ…
     5вҶ’ */
     6вҶ’export enum PrimitiveType {
     7вҶ’  NUM = "num",
     8вҶ’  STR = "str",
     9вҶ’  BOOL = "bool",
    10вҶ’  NULL = "null",
    11вҶ’  UNKNOWN = "unknown",
    12вҶ’}
    13вҶ’
    14вҶ’/**
    15вҶ’ * нғҖмһ… мў…лҘҳ
    16вҶ’ */
    17вҶ’export type Type =
    18вҶ’  | { kind: "primitive"; type: PrimitiveType }
    19вҶ’  | { kind: "array"; elementType: Type }
    20вҶ’  | { kind: "object"; properties: Map<string, Type> }
    21вҶ’  | { kind: "fn"; paramTypes: Type[]; returnType: Type; capabilities?: Capability[] }
    22вҶ’  | { kind: "union"; types: Type[] }
    23вҶ’  | { kind: "never" };
    24вҶ’
    25вҶ’/**
    26вҶ’ * Phase 6: Capability нғҖмһ… м •мқҳ
    27вҶ’ */
    28вҶ’export type CapabilityKind =
    29вҶ’  | "read_file"
    30вҶ’  | "write_file"
    31вҶ’  | "network"
    32вҶ’  | "spawn_process"
    33вҶ’  | "execute_code"
    34вҶ’
    35вҶ’export interface Capability {
    36вҶ’  cap: CapabilityKind
    37вҶ’  arg?: string
    38вҶ’}
    39вҶ’
    40вҶ’/**
    41вҶ’ * нғҖмһ… кІҖмӮ¬ мҳӨлҘҳ
    42вҶ’ */
    43вҶ’export interface TypeCheckError {
    44вҶ’  message: string
    45вҶ’  line?: number
    46вҶ’  column?: number
    47вҶ’  variable?: string
    48вҶ’  expected?: Type
    49вҶ’  actual?: Type
    50вҶ’}
    51вҶ’
    52вҶ’/**
    53вҶ’ * нғҖмһ… кІҖмӮ¬ кІ°кіј
    54вҶ’ */
    55вҶ’export interface TypeCheckResult {
    56вҶ’  success: boolean
    57вҶ’  errors: TypeCheckError[]
    58вҶ’  types?: Map<string, Type>
    59вҶ’}
    60вҶ’
    61вҶ’/**
    62вҶ’ * м ңм•Ҫ мЎ°кұҙ
    63вҶ’ */
    64вҶ’export interface Constraint {
    65вҶ’  variable: string
    66вҶ’  expectedType: Type
    67вҶ’  actualType?: Type
    68вҶ’  location?: { line: number; column: number }
    69вҶ’}
    70вҶ’
    71вҶ’/**
    72вҶ’ * м¶©лҸҢ ліҙкі м„ң
    73вҶ’ */
    74вҶ’export interface ConflictReport {
    75вҶ’  variable: string
    76вҶ’  type1: Type
    77вҶ’  type2: Type
    78вҶ’  message: string
    79вҶ’}
    80вҶ’
    81вҶ’/**
    82вҶ’ * нғҖмһ… нҳёнҷҳм„ұ нҷ•мқё
    83вҶ’ */
    84вҶ’export function typesCompatible(type1: Type, type2: Type): boolean {
    85вҶ’  // Same type
    86вҶ’  if (JSON.stringify(type1) === JSON.stringify(type2)) {
    87вҶ’    return true
    88вҶ’  }
    89вҶ’
    90вҶ’  // Unknown type accepts anything (check BEFORE primitive check)
    91вҶ’  if (type1.kind === "primitive" && type1.type === PrimitiveType.UNKNOWN) {
    92вҶ’    return true
    93вҶ’  }
    94вҶ’  if (type2.kind === "primitive" && type2.type === PrimitiveType.UNKNOWN) {
    95вҶ’    return true
    96вҶ’  }
    97вҶ’
    98вҶ’  // Primitive types
    99вҶ’  if (type1.kind === "primitive" && type2.kind === "primitive") {
   100вҶ’    return type1.type === type2.type
   101вҶ’  }
   102вҶ’
   103вҶ’  // Array types
   104вҶ’  if (type1.kind === "array" && type2.kind === "array") {
   105вҶ’    return typesCompatible(type1.elementType, type2.elementType)
   106вҶ’  }
   107вҶ’
   108вҶ’  // Union types - check if type2 is in union
   109вҶ’  if (type2.kind === "union") {
   110вҶ’    return type2.types.some((t) => typesCompatible(type1, t))
   111вҶ’  }
   112вҶ’
   113вҶ’  return false
   114вҶ’}
   115вҶ’
   116вҶ’/**
   117вҶ’ * нғҖмһ… л¬ёмһҗм—ҙ н‘ңнҳ„
   118вҶ’ */
   119вҶ’export function typeToString(type: Type): string {
   120вҶ’  switch (type.kind) {
   121вҶ’    case "primitive":
   122вҶ’      return type.type
   123вҶ’
   124вҶ’    case "array":
   125вҶ’      return `array[${typeToString(type.elementType)}]`
   126вҶ’
   127вҶ’    case "object":
   128вҶ’      const props = Array.from(type.properties.entries())
   129вҶ’        .map(([k, v]) => `${k}: ${typeToString(v)}`)
   130вҶ’        .join(", ")
   131вҶ’      return `object{${props}}`
   132вҶ’
   133вҶ’    case "fn":
   134вҶ’      const params = type.paramTypes.map(typeToString).join(", ")
   135вҶ’      return `(${params}) -> ${typeToString(type.returnType)}`
   136вҶ’
   137вҶ’    case "union":
   138вҶ’      return type.types.map(typeToString).join(" | ")
   139вҶ’
   140вҶ’    case "never":
   141вҶ’      return "never"
   142вҶ’  }
   143вҶ’}
   144вҶ’
   145вҶ’/**
   146вҶ’ * нғҖмһ… нҢҢмӢұ (л¬ёмһҗм—ҙ вҶ’ Type)
   147вҶ’ */
   148вҶ’export function parseType(typeStr: string): Type {
   149вҶ’  typeStr = typeStr.trim()
   150вҶ’
   151вҶ’  // Primitive types
   152вҶ’  if (typeStr === "num") {
   153вҶ’    return { kind: "primitive", type: PrimitiveType.NUM }
   154вҶ’  }
   155вҶ’  if (typeStr === "str") {
   156вҶ’    return { kind: "primitive", type: PrimitiveType.STR }
   157вҶ’  }
   158вҶ’  if (typeStr === "bool") {
   159вҶ’    return { kind: "primitive", type: PrimitiveType.BOOL }
   160вҶ’  }
   161вҶ’  if (typeStr === "null") {
   162вҶ’    return { kind: "primitive", type: PrimitiveType.NULL }
   163вҶ’  }
   164вҶ’
   165вҶ’  // Array types
   166вҶ’  if (typeStr.startsWith("array[") && typeStr.endsWith("]")) {
   167вҶ’    const elementTypeStr = typeStr.substring(6, typeStr.length - 1)
   168вҶ’    return {
   169вҶ’      kind: "array",
   170вҶ’      elementType: parseType(elementTypeStr),
   171вҶ’    }
   172вҶ’  }
   173вҶ’
   174вҶ’  // Union types
   175вҶ’  if (typeStr.includes(" | ")) {
   176вҶ’    const types = typeStr.split(" | ").map((t) => parseType(t.trim()))
   177вҶ’    return { kind: "union", types }
   178вҶ’  }
   179вҶ’
   180вҶ’  // Default to unknown
   181вҶ’  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   182вҶ’}
   183вҶ’
   184вҶ’/**
   185вҶ’ * м—°мӮ° кІ°кіј нғҖмһ… кІ°м •
   186вҶ’ */
   187вҶ’export function getOperationResultType(
   188вҶ’  op: string,
   189вҶ’  leftType: Type,
   190вҶ’  rightType: Type
   191вҶ’): Type {
   192вҶ’  // Primitive operations
   193вҶ’  if (
   194вҶ’    leftType.kind === "primitive" &&
   195вҶ’    rightType.kind === "primitive"
   196вҶ’  ) {
   197вҶ’    const left = leftType.type
   198вҶ’    const right = rightType.type
   199вҶ’
   200вҶ’    // Numeric operations
   201вҶ’    if (op === "Add") {
   202вҶ’      if (left === PrimitiveType.NUM && right === PrimitiveType.NUM) {
   203вҶ’        return { kind: "primitive", type: PrimitiveType.NUM }
   204вҶ’      }
   205вҶ’      // String concatenation
   206вҶ’      if (left === PrimitiveType.STR || right === PrimitiveType.STR) {
   207вҶ’        return { kind: "primitive", type: PrimitiveType.STR }
   208вҶ’      }
   209вҶ’    }
   210вҶ’
   211вҶ’    if (
   212вҶ’      (op === "Sub" || op === "Mul" || op === "Div" || op === "Mod") &&
   213вҶ’      left === PrimitiveType.NUM &&
   214вҶ’      right === PrimitiveType.NUM
   215вҶ’    ) {
   216вҶ’      return { kind: "primitive", type: PrimitiveType.NUM }
   217вҶ’    }
   218вҶ’
   219вҶ’    // Comparison operations
   220вҶ’    if (
   221вҶ’      op === "Eq" ||
   222вҶ’      op === "Neq" ||
   223вҶ’      op === "Lt" ||
   224вҶ’      op === "Gt" ||
   225вҶ’      op === "Lte" ||
   226вҶ’      op === "Gte"
   227вҶ’    ) {
   228вҶ’      return { kind: "primitive", type: PrimitiveType.BOOL }
   229вҶ’    }
   230вҶ’
   231вҶ’    // Logical operations
   232вҶ’    if (
   233вҶ’      (op === "And" || op === "Or") &&
   234вҶ’      left === PrimitiveType.BOOL &&
   235вҶ’      right === PrimitiveType.BOOL
   236вҶ’    ) {
   237вҶ’      return { kind: "primitive", type: PrimitiveType.BOOL }
   238вҶ’    }
   239вҶ’  }
   240вҶ’
   241вҶ’  // Array operations
   242вҶ’  if (op === "Add" && leftType.kind === "array" && rightType.kind === "array") {
   243вҶ’    // Array concatenation results in array
   244вҶ’    return leftType
   245вҶ’  }
   246вҶ’
   247вҶ’  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   248вҶ’}
   249вҶ’
   250вҶ’/**
   251вҶ’ * нғҖмһ… мўҒнҳҖм§җ (Type Narrowing)
   252вҶ’ */
   253вҶ’export function narrowType(type: Type, condition: Type): Type {
   254вҶ’  // Union нғҖмһ…м—җм„ң мқјл¶Җл§Ң м„ нғқ
   255вҶ’  if (type.kind === "union") {
   256вҶ’    for (const t of type.types) {
   257вҶ’      if (typesCompatible(t, condition)) {
   258вҶ’        return t
   259вҶ’      }
   260вҶ’    }
   261вҶ’  }
   262вҶ’
   263вҶ’  return type
   264вҶ’}
   265вҶ’
   266вҶ’/**
   267вҶ’ * нғҖмһ… нҷ•лҢҖ (Type Widening)
   268вҶ’ */
   269вҶ’export function widenType(...types: Type[]): Type {
   270вҶ’  if (types.length === 0) {
   271вҶ’    return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   272вҶ’  }
   273вҶ’
   274вҶ’  if (types.length === 1) {
   275вҶ’    return types[0]
   276вҶ’  }
   277вҶ’
   278вҶ’  // м—¬лҹ¬ нғҖмһ…мқ„ UnionмңјлЎң кІ°н•©
   279вҶ’  const uniqueTypes = types.filter(
   280вҶ’    (t, i, arr) =>
   281вҶ’      arr.findIndex((u) => JSON.stringify(u) === JSON.stringify(t)) === i
   282вҶ’  )
   283вҶ’
   284вҶ’  if (uniqueTypes.length === 1) {
   285вҶ’    return uniqueTypes[0]
   286вҶ’  }
   287вҶ’
   288вҶ’  return { kind: "union", types: uniqueTypes }
   289вҶ’}
   290вҶ’
   291вҶ’/**
   292вҶ’ * нғҖмһ… м¶”лЎ  кё°ліё к·ңм№ҷ
   293вҶ’ */
   294вҶ’export function inferTypeFromValue(value: any): Type {
   295вҶ’  if (value === null || value === undefined) {
   296вҶ’    return { kind: "primitive", type: PrimitiveType.NULL }
   297вҶ’  }
   298вҶ’
   299вҶ’  switch (typeof value) {
   300вҶ’    case "number":
   301вҶ’      return { kind: "primitive", type: PrimitiveType.NUM }
   302вҶ’    case "string":
   303вҶ’      return { kind: "primitive", type: PrimitiveType.STR }
   304вҶ’    case "boolean":
   305вҶ’      return { kind: "primitive", type: PrimitiveType.BOOL }
   306вҶ’    default:
   307вҶ’      return { kind: "primitive", type: PrimitiveType.UNKNOWN }
